import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { generateWorld } from "../shared/worldgen.ts";

/**
 * Reroll the committed world (shared/world-map.ts) from the generator. The
 * checked-in file is the truth the game reads — hand-edits to it survive until
 * someone deliberately reruns this script.
 */
const world = generateWorld();
const out = `/**
 * The world map — GENERATED by bin/generate-world, then COMMITTED and owned by
 * hand: edit tiles or seeds here directly (assertZones + the worldgen tests
 * validate edits); rerunning the generator overwrites the whole file.
 */
import type { BigHog, Coord, GroundItemSeed } from "./constants";

export const WORLD_SPAWN: Coord = ${JSON.stringify(world.spawn)};

export const WORLD_TILES: readonly string[] = [
${world.tiles.map((row) => `  ${JSON.stringify(row)},`).join("\n")}
];

export const WORLD_BOULDERS: readonly Coord[] = ${JSON.stringify(world.boulders)};

export const WORLD_HOGS: readonly Coord[] = ${JSON.stringify(world.hogs)};

export const WORLD_ITEMS: readonly GroundItemSeed[] = ${JSON.stringify(world.items)};

export const WORLD_BIG_HOGS: readonly BigHog[] = ${JSON.stringify(world.bigHogs)};
`;
writeFileSync(fileURLToPath(new URL("../shared/world-map.ts", import.meta.url)), out);
console.log(`world committed: ${world.tiles.length} rows, ${world.boulders.length} boulders, ${world.hogs.length} hogs`);
